  <Stack direction="column" gap="400">
    <Stack direction="column" gap="200">
      <Text fontSize="sm" fontWeight="semibold">Hour only</Text>
      <TimeInput
        granularity="hour"
        aria-label="Hour granularity"
        defaultValue={new Time(14, 30, 45)}
      />
    </Stack>
    <Stack direction="column" gap="200">
