      <TimeInput
        granularity="minute"
        aria-label="Minute granularity"
        defaultValue={new Time(14, 30, 45)}
      />
    </Stack>
    <Stack direction="column" gap="200">
      <Text fontSize="sm" fontWeight="semibold">Hour, minute, and second</Text>
      <TimeInput
        granularity="second"
        aria-label="Second granularity"
        defaultValue={new Time(14, 30, 45)}
      />
    </Stack>
  </Stack>
